CREATE OR REPLACE FUNCTION awa.mark_dirty_keys_delete() RETURNS trigger AS $$
BEGIN
    INSERT INTO awa.admin_dirty_queues (queue)
    SELECT DISTINCT queue FROM old_rows ORDER BY queue
    ON CONFLICT (queue) DO NOTHING;

    INSERT INTO awa.admin_dirty_kinds (kind)
    SELECT DISTINCT kind FROM old_rows ORDER BY kind
    ON CONFLICT (kind) DO NOTHING;

    RETURN NULL;
END;
$$ LANGUAGE plpgsql

create or replace function assert.equal(_expected anyelement, _actual anyelement, _comment text default '') returns boolean as $$
    begin

        IF _expected != _actual THEN
            return assert.fail(format('Not equal: %s (expected) != %s (actual)', _expected, _actual), _comment);
        END IF;

        return true;
    end;
$$ language plpgsql security definer

create function public.authorize(
  requested_permission app_permission
)
returns boolean as $$
declare
  bind_permissions int;
begin
  select count(*)
  from public.role_permissions
  where role_permissions.permission = authorize.requested_permission
    and role_permissions.role = (auth.jwt() ->> 'user_role')::public.app_role
  into bind_permissions;

  return bind_permissions > 0;
end;
$$ language plpgsql security definer set search_path = public;

create or replace function assert.not_null(_value text, _comment text default '') returns boolean as $$
    begin

        IF _value IS NULL THEN
            return assert.fail('Expected value not to be null.', _comment);
        END if;

        return true;
    end;
$$ language plpgsql security definer

